def average(nums):
    if not nums:
        raise ValueError("nums must not be empty")
    total = 0
    for n in nums:
        total += n
    return total / len(nums)

def transpose(matrix):
    rows = len(matrix)
    cols = len(matrix[0])
    result = [[None] * rows for _ in range(cols)]
    for r in range(rows):
        for c in range(cols):
            result[c][r] = matrix[r][c]
    return result

def is_prime(n):
    if n < 2:
        return False
    if n % 2 == 0:
        return n == 2
    divisor = 3
    while divisor * divisor <= n:
        if n % divisor == 0:
            return False
        divisor += 2
    return True

def get_page(items, page, page_size):
    if page < 0:
        raise ValueError("page must be non-negative")
    if page_size <= 0:
        raise ValueError("page_size must be positive")
    start = page * page_size
    return items[start:start + page_size]

def rotate_left(items, k):
    if not items:
        return []
    n = len(items)
    k = k % n
    return items[k:] + items[:k]

def group_anagrams(words):
    groups = {}
    first_occurrence = {}

    for word in words:
        # Use sorted characters as signature (case-sensitive)
        signature = tuple(sorted(word))

        if signature not in groups:
            groups[signature] = []
            first_occurrence[signature] = len(first_occurrence)

        groups[signature].append(word)

    # Sort groups by first occurrence and return
    sorted_signatures = sorted(first_occurrence.keys(), key=lambda s: first_occurrence[s])
    return [groups[sig] for sig in sorted_signatures]

def longest_streak(values):
    if not values:
        return 0

    max_streak = 1
    current_streak = 1

    for i in range(1, len(values)):
        if values[i] == values[i - 1]:
            current_streak += 1
            max_streak = max(max_streak, current_streak)
        else:
            current_streak = 1

    return max_streak

def parse_settings(lines):
    result = {}
    for line in lines:
        stripped = line.strip()
        if not stripped:
            continue
        if '=' not in stripped:
            raise ValueError(f"Line without '=': {stripped!r}")
        key, sep, value = stripped.partition('=')
        key = key.strip()
        if not key:
            raise ValueError(f"Empty key in line: {stripped!r}")
        result[key] = value.strip()
    return result
